package org.apache.commons.math.special;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.special.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.special.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.assertEquals;
import org.apache.commons.math.special.Gamma;

public class StepDefs {

    private double a;
    private double x;
    private double result;
    private double expected;
    private double tolerance;

    @Given("the value a is {double}")
    public void the_value_a_is(double a) {
        this.a = a;
    }

    @Given("the value x is {double}")
    public void the_value_x_is(double x) {
        this.x = x;
    }

    @When("I calculate regularizedGammaP(a, x)")
    public void i_calculate_regularizedGammaP() {
        try {
            this.result = Gamma.regularizedGammaP(this.a, this.x);
        } catch (Exception e) {
            // Capture any exceptions if they occur
            throw new RuntimeException("Error calculating regularizedGammaP: " + e.getMessage(), e);
        }
    }

    @Then("the result should be {double}")
    public void the_result_should_be(double expected) {
        this.expected = expected;
        assertEquals("Result should match expected value", expected, result, 0);
    }

    @Then("the calculation precision should satisfy a tolerance of {double}")
    public void the_calculation_precision_should_satisfy_a_tolerance_of(double tolerance) {
        this.tolerance = tolerance;
        double difference = Math.abs(expected - result);
        assertEquals("Result should match expected value within tolerance", expected, result, tolerance);
    }
}

